// ═══════════════════════════════════════════════════════════
// SELF-CONSISTENCY VALIDATION
// Compares the three LLM runs. If they agree → high confidence.
// If they disagree → lower confidence → MANUAL_REVIEW.
// ═══════════════════════════════════════════════════════════

// n8n passes multiple inputs from the three HTTP Request nodes.
// We need to get results from all three runs.
// Each run was connected as a separate input to this node.
const run1Response = $('Extract Run 1 (temp 0.0)').first().json;
const run2Response = $('Extract Run 2 (temp 0.3)').first().json;
const run3Response = $('Extract Run 3 (temp 0.6)').first().json;
const pair = $('Split In Batches1').first().json;

// ── Parse helper ─────────────────────────────────────────────
function parseEvidence(llmResponse) {
  let raw = llmResponse.choices?.[0]?.message?.content || '';
  raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  const objStart = raw.indexOf('{');
  const objEnd = raw.lastIndexOf('}');
  if (objStart === -1 || objEnd === -1) return null;
  try {
    const obj = JSON.parse(
      raw.substring(objStart, objEnd + 1).replace(/,\s*([\]\}])/g, '$1')
    );
    // Normalise value to float if it's a string number
    if (typeof obj.value === 'string') {
      const cleaned = obj.value.replace(/[₹,\s]/g, '');
      const asFloat = parseFloat(cleaned);
      obj.value = isNaN(asFloat) ? obj.value : asFloat; // keep string if not numeric
    }
    return obj;
  } catch (e) {
    return null;
  }
}

// ── Normalise value for comparison ───────────────────────────
// Converts to string for reliable equality check across types
function normaliseForCompare(val) {
  if (val === null || val === undefined) return '__NULL__';
  if (typeof val === 'number') return val.toFixed(2);
  return String(val).toLowerCase().trim()
    .replace(/[₹,\s]/g, '')
    .replace(/crore/g, '0000000')
    .replace(/lakh/g, '00000');
}

const e1 = parseEvidence(run1Response);
const e2 = parseEvidence(run2Response);
const e3 = parseEvidence(run3Response);

const parsedRuns = [e1, e2, e3].filter(Boolean);

// If all three failed to parse — definitive not_found
if (parsedRuns.length === 0) {
  return [{ json: {
    ...pair,
    value: null,
    unit: null,
    source_chunk_ref: null,
    source_page: null,
    quoted_text: null,
    confidence: 0.0,
    not_found_reason: 'All 3 LLM runs failed to produce parseable JSON',
    extraction_method: 'consistency_all_failed',
    consistency_detail: { run1: null, run2: null, run3: null, agreement: false },
    extracted_at: new Date().toISOString()
  } }];
}

// ── Compare the values across runs ───────────────────────────
const values = parsedRuns.map(e => normaliseForCompare(e?.value));
const uniqueValues = [...new Set(values)];

// Count how many runs agree on each value
const valueCounts = {};
for (const v of values) {
  valueCounts[v] = (valueCounts[v] || 0) + 1;
}

// Find the majority value (value that appears most)
const majorityValue = Object.entries(valueCounts).sort((a, b) => b[1] - a[1])[0][0];
const majorityCount = valueCounts[majorityValue];

// ── Agreement logic ───────────────────────────────────────────
// All 3 agree → FULL agreement → boost confidence
// 2 of 3 agree → PARTIAL agreement → use majority but flag
// All 3 disagree → NO agreement → escalate to MANUAL_REVIEW

const FULL_AGREEMENT  = majorityCount === 3;
const PARTIAL_AGREEMENT = majorityCount === 2;
const NO_AGREEMENT = uniqueValues.length === parsedRuns.length && parsedRuns.length > 1;

// Pick the winner — the run whose value matches the majority
// If tied (all different), pick run1 (temp 0.0) as most deterministic
let winner = parsedRuns.find(e => normaliseForCompare(e?.value) === majorityValue) || e1 || parsedRuns[0];

// ── Confidence adjustment ─────────────────────────────────────
let finalConfidence = winner.confidence ?? 0.0;
let consistencyNote = '';
let forceManualReview = false;

if (FULL_AGREEMENT && majorityValue !== '__NULL__') {
  // All 3 found the same value — strong signal, boost confidence
  finalConfidence = Math.min(1.0, finalConfidence + 0.10);
  consistencyNote = `All 3 runs agreed on value: ${majorityValue}`;

} else if (FULL_AGREEMENT && majorityValue === '__NULL__') {
  // All 3 found nothing — confident not_found
  finalConfidence = 0.95;
  consistencyNote = 'All 3 runs agree: value not found in document';

} else if (PARTIAL_AGREEMENT && majorityValue !== '__NULL__') {
  // 2 of 3 agree — moderate confidence, keep as-is or slight penalty
  finalConfidence = Math.max(0.0, finalConfidence - 0.05);
  const dissenter = parsedRuns.find(e => normaliseForCompare(e?.value) !== majorityValue);
  consistencyNote = `2 of 3 runs agreed. Dissenting run extracted: ${dissenter?.value ?? 'null'}`;

} else if (PARTIAL_AGREEMENT && majorityValue === '__NULL__') {
  // 2 of 3 found nothing, 1 found something — uncertain
  finalConfidence = 0.45;
  forceManualReview = true;
  consistencyNote = '2 of 3 runs found no value. 1 run found a value. Flagging for manual review.';

} else if (NO_AGREEMENT) {
  // All runs found different values — the extraction is unreliable
  finalConfidence = 0.30;
  forceManualReview = true;
  consistencyNote = `All 3 runs disagreed. Values were: ${parsedRuns.map(e => e?.value ?? 'null').join(' | ')}`;
}

// Clamp confidence
finalConfidence = Math.min(1.0, Math.max(0.0, finalConfidence));

// ── Force MANUAL_REVIEW if confidence still too low ───────────
if (finalConfidence < 0.60 && !forceManualReview) {
  forceManualReview = true;
  consistencyNote += ` Confidence ${finalConfidence.toFixed(2)} below 0.60 threshold.`;
}

return [{
  json: {
    ...pair,
    value: forceManualReview && NO_AGREEMENT ? null : (winner.value ?? null),
    unit: winner.unit ?? null,
    source_chunk_ref: winner.source_chunk_ref ?? null,
    source_page: winner.source_page ?? null,
    quoted_text: winner.quoted_text ?? null,
    confidence: finalConfidence,
    not_found_reason: (winner.value === null) ? (winner.not_found_reason ?? 'Not found') : null,
    extraction_method: forceManualReview ? 'consistency_manual_review' : 'consistency_validated',
    consistency_detail: {
      run1_value: e1?.value ?? null,
      run2_value: e2?.value ?? null,
      run3_value: e3?.value ?? null,
      full_agreement: FULL_AGREEMENT,
      partial_agreement: PARTIAL_AGREEMENT,
      no_agreement: NO_AGREEMENT,
      majority_value: majorityValue,
      majority_count: majorityCount,
      note: consistencyNote
    },
    force_manual_review: forceManualReview,
    extracted_at: new Date().toISOString()
  }
}];

const bidder_ids = $('Webhook Trigger1').first().json.body.bidder_ids || [];
const tender_id = $('Webhook Trigger1').first().json.body.tender_id;
const criteria = $input.all().map(item => item.json);

if (criteria.length === 0) throw new Error('No confirmed criteria found.');
if (bidder_ids.length === 0) throw new Error('No bidder_ids provided.');

const pairs = [];
for (const bidder_id of bidder_ids) {
  for (const criterion of criteria) {
    pairs.push({
      tender_id, bidder_id,
      criterion_id: criterion.id,
      criterion_name: criterion.name,
      criterion_type: criterion.type,
      criterion_description: criterion.description,
      threshold_value: criterion.threshold_value ?? null,
      threshold_unit: criterion.threshold_unit ?? null,
      mandatory: criterion.mandatory,
      source_section: criterion.source_section,
      embedding_query: [criterion.name, criterion.description, criterion.source_text || ''].filter(Boolean).join('. ')
    });
  }
}

return pairs.map(p => ({ json: p }));

const embeddingResponse = $input.first().json;
const vector = embeddingResponse.data?.[0]?.embedding;
if (!vector || vector.length === 0) throw new Error('Embedding failed.');
const pair = $('Split In Batches1').first().json;
return [{ json: { ...pair, vector } }];

const qdrantResponse = $input.first().json;
const searchResults = qdrantResponse.result || [];
const pair = $('Split In Batches1').first().json;

const chunks = searchResults.map((r, i) => {
  const p = r.payload || {};
  const score = r.score ? ` (relevance: ${r.score.toFixed(2)})` : '';
  return `[Chunk ${i + 1}, Page ${p.page_num || '?'}${score}]\n${p.text || ''}`;
}).join('\n\n---\n\n');

return [{
  json: {
    ...pair,
    context_chunks: chunks,
    chunk_count: searchResults.length,
    no_chunks_found: searchResults.length === 0,
    raw_search_results: searchResults.map(r => ({
      score: r.score,
      page_num: r.payload?.page_num,
      block_type: r.payload?.block_type,
      text_preview: (r.payload?.text || '').substring(0, 100)
    }))
  }
}];

const pair = $input.first().json;
const generatedId = `${pair.tender_id}_${pair.bidder_id}_${pair.criterion_id}_${Date.now()}`;
return [{ json: {
  id: generatedId,
  tender_id: pair.tender_id,
  bidder_id: pair.bidder_id,
  criterion_id: pair.criterion_id,
  extracted_value: null,
  source_pages: [],
  source_text: null,
  confidence: 0.0,
  not_found_reason: 'No relevant document chunks found in Qdrant for this bidder.',
  extraction_method: 'qdrant_empty',
  extracted_at: new Date().toISOString()
} }];

// Build the shared LLM body template.
// Three runs will use this same prompt but with different temperatures.
// Temperatures: 0.0 (deterministic), 0.3 (slight variation), 0.6 (more variation)
// If all three agree on the value → high confidence confirmed.
// If they disagree → lower confidence, escalate to MANUAL_REVIEW.

const pair = $input.first().json;

const systemPrompt = `You are a document evidence extractor for Indian government procurement evaluation.
Your job: find ONE specific value in the provided document chunks.

RULES (non-negotiable):
1. Return ONLY what is explicitly written in the chunks. Zero inference. Zero estimation.
2. If the value is not clearly present, return null for value.
3. quoted_text must be copied VERBATIM from the chunk — exact words, exact spelling.
4. Never calculate, derive, or average values.
5. Return ONLY a JSON object — no markdown, no fences, no explanation.
Start your response with { and end with }
6. If the criterion is qualitative (e.g., AI capabilities, certifications, features, compliance),
   DO NOT extract numeric financial values.
   Instead, return value = null and extract the full relevant descriptive quoted_text.
7. Prefer chunks where the criterion keyword or section heading directly matches the criterion name.

Return exactly this shape:
{
  "value": 21000000,
  "unit": "INR",
  "source_chunk_ref": 2,
  "source_page": 4,
  "quoted_text": "exact words from the chunk",
  "confidence": 0.91,
  "not_found_reason": null
}

If NOT found:
{
  "value": null,
  "unit": null,
  "source_chunk_ref": null,
  "source_page": null,
  "quoted_text": null,
  "confidence": 0.0,
  "not_found_reason": "one sentence explaining why"
}`;

const userPrompt = `Criterion to find: ${pair.criterion_name}\nFull requirement: ${pair.criterion_description}\nThreshold: ${pair.threshold_value} ${pair.threshold_unit}\n\nDocument chunks from this bidder's submission:\n\n${pair.context_chunks}\n\nFind the evidence for this criterion in the chunks above. Return the JSON object only.`;

// Build three request bodies with different temperatures
const makeBody = (temp) => JSON.stringify({
  model: $('SetModel').first().json.model_name,
  temperature: temp,
  max_tokens: 1000,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
});

return [{
  json: {
    ...pair,
    llm_body_run1: makeBody(0.0),
    llm_body_run2: makeBody(0.3),
    llm_body_run3: makeBody(0.6)
  }
}];

function makeId(item) {
  return `${item.tender_id}_${item.bidder_id}_${item.criterion_id}_${Date.now()}`;
}

return $input.all().map(item => {
  const e = item.json;
  return {
    json: {
      id: makeId(e),
      tender_id: e.tender_id,
      bidder_id: e.bidder_id,
      criterion_id: e.criterion_id,
      extracted_value: e.value !== null && e.value !== undefined ? String(e.value) : null,
      source_text: e.quoted_text || null,
      source_pages: e.source_page !== null && e.source_page !== undefined ? [e.source_page] : [],
      confidence: typeof e.confidence === 'number' ? Math.min(1, Math.max(0, e.confidence)) : 0,
      extraction_method: e.extraction_method || 'rag',
      // Pass consistency_detail through for audit log
      consistency_detail: e.consistency_detail || null,
      force_manual_review: e.force_manual_review || false,
      extracted_at: e.extracted_at || new Date().toISOString()
    }
  };
});

const webhookData = $('Webhook Trigger1').first().json.body;
return [{ json: {
  tender_id: webhookData.tender_id,
  bidder_ids: webhookData.bidder_ids,
  status: 'evidence_extraction_complete',
  completed_at: new Date().toISOString()
} }];
